sql:
SELECT author_id, author_name, engagement_score
FROM authors
WHERE is_verified = 1;

SELECT users.username, authors.author_name
FROM users
INNER JOIN authors ON users.user_id = authors.author_id;

SELECT author_name
FROM authors
WHERE author_id = (SELECT author_id FROM users WHERE username = 'john_doe');

SELECT AVG(engagement_score) AS average_engagement_score
FROM (
  SELECT engagement_score, NTILE(10) OVER (ORDER BY followers_count DESC) AS decile
  FROM authors
) AS ranked_authors
WHERE decile = 1;

SELECT a.*
FROM authors a
WHERE a.tweets_count > 1000;

SELECT author_name, followers_count
FROM authors
WHERE followers_count = (SELECT MAX(followers_count) FROM authors);

SELECT author_name, bio, ACOSH(LENGTH(bio)) AS bio_complexity
FROM authors
WHERE is_verified = 1;

external_knowledge:
- 'Whispers and voices' metaphorically refers to the content of tweets and usernames;
- 'Designated navigators' symbolizes the authors of the tweets;
- 'Vast ocean of social chatter' symbolizes the entire database of tweets;
- 'Lighthouses of trustworthiness and activity' metaphorically refers to the conditions where `is_verified = 1` and `is_active = 1`;
- The names 'Rick Scott' and 'Marco Rubio' are direct references to specific authors in the database.

